func verify(expected, supplied []byte, maximum int) bool {
	if len(expected) != 32 || len(supplied) != 32 || len(supplied) > maximum { return false }
	return subtle.ConstantTimeCompare(expected, supplied) == 1
}

func main() {
	expected, changed := make([]byte, 32), make([]byte, 32)
	expected[0], changed[0] = 2, 3
	fmt.Printf("same=%t changed=%t whole_app_constant_time_unproved=true\n", verify(expected, expected, 32), verify(expected, changed, 32))
}
